INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100101, 155, "人助けが大好き！　前向き格闘娘", "獣人族", 16, "A", "トゥインクルウィッシュ", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0, 8, "東山奈央", 44, 2, 27, "ヒヨリ", "人助け、応援");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100201, 158, "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 17, "O", "トゥインクルウィッシュ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0, 4, "種田梨沙", 47, 2, 5, "ユイ", "料理、人間観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100301, 163, "クールで何事にも真っ直ぐな剣士", "魔族", 18, "B", "トゥインクルウィッシュ", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0, 1, "早見沙織", 46, 2, 12, "レイ", "読書、乗馬、お茶");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100401, 128, "探検好きのイタズラっ子", "ヒューマン", 9, "O", "リトルリリカル", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 0, 8, "諸星すみれ", 27, 5, 10, "ミソギ", "いたずら、探検");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100501, 146, "ヒーローに憧れる騎士見習いの少女", "獣人族", 12, "O", "王宮騎士団（NIGHTMARE）", "？？？", 0, 11, "下田麻美", 40, 8, 25, "マツリ", "ヒーローごっこ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100601, 150, "甘え上手なみんなの人気者", "魔族", 13, "O", "悪魔偽王国軍（ディアボロス）", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 0, 11, "浅倉杏美", 42, 7, 22, "アカリ", "サックス");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100701, 130, "プリン大好きゴースト娘", "魔族", 14, "B", "悪魔偽王国軍（ディアボロス）", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 0, 1, "雨宮天", 32, 7, 23, "ミヤコ", "プリンを食べること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100801, 150, "ボクは誰よりも美しい", "エルフ", 14, "AB", "ヴァイスフリューゲル　ランドソル支部", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 0, 10, "大空直美", 40, 15, 10, "ユキ", "鏡で自分を見ること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (100901, 159, "前世を信じる中二病患者、「疾風の冥姫」", "魔族", 17, "A", "トワイライトキャラバン", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 0, 7, "髙野麻美", 45, 13, 5, "アンナ", "小説執筆");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101001, 155, "マホマホ王国のプリンセス", "獣人族", 16, "O", "自警団（カォン）", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0, 9, "内田真礼", 42, 10, 22, "マホ", "空想、ぬいぐるみ集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101101, 156, "人懐っこくてマシンガントークな妹系少女", "ヒューマン", 15, "A", "ラビリンス", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 0, 8, "阿澄佳奈", 44, 3, 25, "リノ", "お裁縫");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101201, 156, "みんなのために超能力を使う眠り姫", "エルフ", 17, "A", "フォレスティエ", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 0, 12, "大橋彩香", 46, 6, 24, "ハツネ", "妹と遊ぶこと、二度寝、昼寝、早寝");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101301, 166, "オタク全開な魔法少女", "魔族", 18, "O", "トワイライトキャラバン", "", 0, 8, "佳村はるか", 55, 13, 21, "ナナカ", "読書、魔法");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101401, 152, "頭脳明晰な美少女名探偵", "獣人族", 15, "AB", "自警団（カォン）", "test", 0, 11, "水瀬いのり", 41, 10, 3, "カスミ", "読書、推理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101501, 165, "母性溢れる優しいみんなの「ミサト先生」", "エルフ", 21, "O", "フォレスティエ", "test", 0, 9, "國府田マリ子", 54, 6, 5, "ミサト", "絵本作り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101601, 167, "天真爛漫で人気者のカリスマモデル", "魔族", 17, "O", "ルーセント学院", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 0, 4, "上坂すみれ", 48, 14, 10, "スズナ", "ファッション");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101701, 158, "いつでも「なんくるないさ～」な天然娘", "獣人族", 17, "A", "自警団（カォン）", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 0, 7, "高森奈津美", 53, 10, 7, "カオリ", "踊り、空手");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (101801, 162, "多くの男性を魅了する無垢な女教師", "魔族", 23, "B", "ルーセント学院", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 0, 8, "伊藤静", 52, 14, 14, "イオ", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102001, 117, "お歌もにんじんも、ウサギさんも大好き♪", "獣人族", 10, "O", "リトルリリカル", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 0, 4, "日高里菜", 21, 5, 3, "ミミ", "かわいいもの集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102101, 150, "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", 12, "B", "サレンディア救護院", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 0, 6, "植田佳奈", 40, 9, 9, "クルミ", "観劇、おままごと");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102201, 150, "人見知りであまのじゃくな女の子", "魔族", 13, "O", "悪魔偽王国軍（ディアボロス）", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 0, 11, "原紗友里", 40, 7, 22, "ヨリ", "ゲーム全般");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102301, 148, "ぷうきちといつも一緒！", "ヒューマン", 14, "B", "サレンディア救護院", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 0, 5, "芹澤優", 38, 9, 10, "アヤネ", "屋内でできる遊び");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102501, 154, "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", 15, "O", "サレンディア救護院", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 0, 12, "悠木碧", 43, 9, 12, "スズメ", "ご奉仕");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102601, 144, "遊びと睡眠が何より大事なぐうたら娘", "獣人族", 17, "B", "牧場（エリザベスパーク）", "test", 0, 1, "小岩井ことり", 42, 11, 1, "リン", "あんパン");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102701, 154, "運命の相手に一途すぎる乙女", "魔族", 16, "B", "トワイライトキャラバン", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 0, 7, "橋本ちなみ", 43, 13, 30, "エリコ", "実験、裁縫、料理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102801, 156, "救護院を経営する優しい庶民派お嬢様", "エルフ", 17, "A", "サレンディア救護院", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 0, 10, "堀江由衣", 43, 9, 4, "サレン", "経営、お茶会");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (102901, 157, "歌って踊れる大人気アイドル", "ヒューマン", 17, "B", "カルミナ", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 0, 1, "日笠陽子", 40, 4, 24, "ノゾミ", "舞台鑑賞、ダンス");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103001, 163, "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", 16, "O", "ヴァイスフリューゲル　ランドソル支部", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0, 8, "佐藤聡美", 51, 15, 31, "ニノン", "忍法開発");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103101, 157, "占いが得意な霊能少女", "魔族", 18, "AB", "悪魔偽王国軍（ディアボロス）", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0, 12, "大坪由佳", 42, 7, 22, "シノブ", "占い");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103201, 157, "一人前の商人を目指すパワフルお嬢様", "ヒューマン", 18, "AB", "メルクリウス財団", "この私とともにいる限り、\nお金に不自由はさせませんわ！", 0, 3, "松嵜麗", 45, 12, 12, "アキノ", "慈善事業");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103301, 142, "みんなを笑顔にするお笑い牧場主", "ヒューマン", 20, "B", "牧場（エリザベスパーク）", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 0, 3, "新田恵海", 35, 11, 3, "マヒル", "漫才");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103401, 164, "純情でほっとけない大人の女性", "エルフ", 22, "A", "メルクリウス財団", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 0, 3, "今井麻美", 55, 12, 16, "ユカリ", "ウインドーショッピング");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103601, 118, "礼儀正しくしっかり者のちびっ子優等生", "エルフ", 8, "A", "リトルリリカル", "test", 0, 2, "小倉唯", 21, 5, 2, "キョウカ", "お勉強");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103701, 149, "義理堅くてからかい好きな剣術少女", "ヒューマン", 13, "A", "王宮騎士団（NIGHTMARE）", "test", 0, 8, "茅原実里", 43, 8, 11, "トモ", "剣術、年長者をからかう");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (103801, 153, "読書が趣味の病弱少女", "獣人族", 14, "A", "牧場（エリザベスパーク）", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 0, 11, "小清水亜美", 40, 11, 3, "シオリ", "読書、お散歩");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104001, 158, "「友達」に憧れる、エルフの森の女の子", "エルフ", 13, "AB", "フォレスティエ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 0, 6, "花澤香菜", 44, 6, 6, "アオイ", "友達作りのイメトレ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104201, 163, "人々を守るために歌う、唱喚士の少女", "ヒューマン", 17, "O", "カルミナ", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0, 6, "福原綾香", 46, 4, 3, "チカ", "各種楽器");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104301, 168, "男勝りで情に厚いワイルド娘", "獣人族", 17, "O", "自警団（カォン）", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 0, 8, "小松未可子", 54, 10, 9, "マコト", "お菓子作り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104401, 172, "かつては夜を支配した最強の吸血鬼", "魔族", "??", "A", "悪魔偽王国軍（ディアボロス）", "test", 0, 5, "丹下桜", 50, 7, 5, "イリヤ", "世界征服");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104501, 157, "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", 18, "AB", "ヴァイスフリューゲル　ランドソル支部", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 0, 11, "長妻樹里", 49, 15, 19, "クウカ", "小説を読むこと");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104601, 158, "弱きを助け強きをくじく猫娘", "獣人族", 19, "AB", "メルクリウス財団", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0, 3, "沼倉愛美", 48, 12, 1, "タマキ", "猫とたわむれること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104701, 171, "素顔を見せない冷静沈着な女性騎士", "ヒューマン", 25, "A", "王宮騎士団（NIGHTMARE）", "？？？", 0, 10, "川澄綾子", 50, 8, 25, "ジュン", "格闘技、湯浴み");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104801, 163, "仕事も私事も効率優先な傭兵少女", "ヒューマン", 20, "O", "メルクリウス財団", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0, 11, "田所あずさ", 49, 12, 11, "ミフユ", "傭兵などのアルバイト");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (104901, 168, "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 18, "O", "ラビリンス", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0, 10, "生天目仁美", 54, 3, 24, "シズル", "家事全般");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105001, 120, "ちょっとおませな恋に恋する女の子", "魔族", 11, "A", "ルーセント学院", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 0, 1, "久野美咲", 22, 14, 3, "ミサキ", "ファッション誌鑑賞、コスメ集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105101, 166, "実験が趣味の危険な科学者", "ヒューマン", 27, "A", "トワイライトキャラバン", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 0, 3, "三石琴乃", 53, 13, 7, "ミツキ", "研究、実験");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105201, 150, "乙女チックなもふもふアニマル", "獣人族", 17, "A", "牧場（エリザベスパーク）", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 0, 3, "徳井青空", 100, 11, 14, "リマ", "毛繕い、お喋り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105301, 140, "見た目も中身もお子ちゃまな異国の軍人", "ヒューマン", 17, "A", "ヴァイスフリューゲル　ランドソル支部", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 0, 7, "辻あゆみ", 33, 15, 28, "モニカ", "お菓子屋通い");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105401, 153, "ファッション大好きなキュートガール", "ヒューマン", 14, "AB", "カルミナ", "test", 0, 9, "木戸衣吹", 45, 4, 7, "ツムギ", "裁縫");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105501, 155, "どこまでも一途に慕う、純情乙女", "エルフ", 16, "O", "ヴァイスフリューゲル　ランドソル支部", "test", 0, 4, "大関英里", 43, 15, 7, "アユミ", "観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105601, 167, "人情味溢れる粋でいなせな「姉御」", "ヒューマン", 25, "B", "トワイライトキャラバン", "test", 0, 7, "佐藤利奈", 54, 13, 11, "ルカ", "釣り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105701, 156, "空への冒険を夢見る騎空士の少女", "ヒューマン", 17, "O", "？？？", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 0, 3, "金元寿子", 45, "", 10, "ジータ", "冒険、おしゃべり");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105801, 156, "いつも元気な腹ペコ少女", "ヒューマン", 17, "O", "美食殿", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0, 3, "M・A・O", 46, 1, 31, "ペコリーヌ", "食べ歩き、料理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (105901, 140, "主を慕う、小さなガイド役", "エルフ", 11, "B", "美食殿", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0, 5, "伊藤美来", 35, 1, 11, "コッコロ", "瞑想、動植物の飼育");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (106001, 152, "行き倒れの謎のネコミミ魔法使い", "獣人族", 14, "A", "美食殿", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0, 9, "立花理香", 39, 1, 2, "キャル", "猫と遊ぶ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (106101, 148, "さまよえる謎の少女", "ヒューマン", 16, "O", "？？？", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 0, 8, "潘めぐみ", 40, "", 11, "ムイミ", "冒険、思い出話");
