INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (106401, 147, "記憶喪失のドラゴン娘", "ドラゴン族", 14, "B", "美食殿", "", 0, 12, "近藤玲奈", "???", 1, 14, "シェフィ", "読書、ストレッチ");
