INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (106701, 168, "妖しい微笑で全てを見透かす臥竜の頭領", "ドラゴン族", 25, "O", "ドラゴンズネスト", "", 0, 4, "大西沙織", "???", 17, 17, "ホマレ", "絵画、読書");
