INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107001, 149, "研究所に隠れ住む物静かなお姉さん", "エルフ", 24, "O", "？？？", "", 0, 3, "井口裕香", "??", "", 24, "ネネカ", "物真似、芸術鑑賞");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107101, 165, "傍若無人な王宮騎士団副団長", "ヒューマン", 27, "O", "王宮騎士団（NIGHTMARE）", "", 0, 2, "たかはし智秋", "??", 8, 7, "クリスティーナ", "強敵との闘争");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107501, 156, "いつも元気な腹ペコ少女", "ヒューマン", 17, "O", "美食殿", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0, 3, "M・A・O", 46, 1, 31, "ペコリーヌ（サマー）", "食べ歩き、料理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107601, 140, "主を慕う、小さなガイド役", "エルフ", 11, "B", "美食殿", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0, 5, "伊藤美来", 35, 1, 11, "コッコロ（サマー）", "瞑想、動植物の飼育");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107701, 154, "お嬢さまのためにがんばるドジっ娘メイド", "ヒューマン", 15, "O", "サレンディア救護院", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 0, 12, "悠木碧", 43, 9, 12, "スズメ（サマー）", "ご奉仕");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107801, 152, "行き倒れの謎のネコミミ魔法使い", "獣人族", 14, "A", "美食殿", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0, 9, "立花理香", 39, 1, 2, "キャル（サマー）", "猫と遊ぶ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (107901, 158, "弱きを助け強きをくじく猫娘", "獣人族", 19, "AB", "メルクリウス財団", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0, 3, "沼倉愛美", 48, 12, 1, "タマキ（サマー）", "猫とたわむれること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108001, 163, "仕事も私事も効率優先な傭兵少女", "ヒューマン", 20, "O", "メルクリウス財団", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0, 11, "田所あずさ", 49, 12, 11, "ミフユ（サマー）", "傭兵などのアルバイト");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108101, 157, "占いが得意な霊能少女", "魔族", 18, "AB", "悪魔偽王国軍（ディアボロス）", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0, 12, "大坪由佳", 42, 7, 22, "シノブ（ハロウィン）", "占い");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108201, 130, "プリン大好きゴースト娘", "魔族", 14, "B", "悪魔偽王国軍（ディアボロス）", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 0, 1, "雨宮天", 32, 7, 23, "ミヤコ（ハロウィン）", "プリンを食べること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108301, 120, "ちょっとおませな恋に恋する女の子", "魔族", 11, "A", "ルーセント学院", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 0, 1, "久野美咲", 22, 14, 3, "ミサキ（ハロウィン）", "ファッション誌鑑賞、コスメ集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108401, 163, "人々を守るために歌う、唱喚士の少女", "ヒューマン", 17, "O", "カルミナ", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0, 6, "福原綾香", 46, 4, 3, "チカ（クリスマス）", "各種楽器");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108501, 150, "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", 12, "B", "サレンディア救護院", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 0, 6, "植田佳奈", 40, 9, 9, "クルミ（クリスマス）", "観劇、おままごと");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108601, 148, "ぷうきちといつも一緒！", "ヒューマン", 14, "B", "サレンディア救護院", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 0, 5, "芹澤優", 38, 9, 10, "アヤネ（クリスマス）", "屋内でできる遊び");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108701, 155, "人助けが大好き！　前向き格闘娘", "獣人族", 16, "A", "トゥインクルウィッシュ", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0, 8, "東山奈央", 44, 2, 27, "ヒヨリ（ニューイヤー）", "人助け、応援");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108801, 158, "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 17, "O", "トゥインクルウィッシュ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0, 4, "種田梨沙", 47, 2, 5, "ユイ（ニューイヤー）", "料理、人間観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (108901, 163, "クールで何事にも真っ直ぐな剣士", "魔族", 18, "B", "トゥインクルウィッシュ", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0, 1, "早見沙織", 46, 2, 12, "レイ（ニューイヤー）", "読書、乗馬、お茶");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109001, 154, "運命の相手に一途すぎる乙女", "魔族", 16, "B", "トワイライトキャラバン", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 0, 7, "橋本ちなみ", 43, 13, 30, "エリコ（バレンタイン）", "実験、裁縫、料理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109101, 168, "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 18, "O", "ラビリンス", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0, 10, "生天目仁美", 54, 3, 24, "シズル（バレンタイン）", "家事全般");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109201, 156, "英霊と契約を結んだマナリアの天才王女", "ヒューマン", 17, "AB", "？？？", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 0, 12, "日笠陽子", 55, "", 1, "アン", "読書");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109301, 144, "マナリア魔法学院の新入生", "ヒューマン", 16, "O", "？？？", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 0, 2, "こやまきみこ", 45, "", 4, "ルゥ", "食べること、眠ること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109401, 167, "人を超越した力を有す心優しい竜姫", "半人半竜", 17, "B", "？？？", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 0, 11, "福原綾香", 67, "", 3, "グレア", "ピアノ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109501, 157, "妄想大好き！　ほんとは照れ屋な女の子", "ヒューマン", 18, "AB", "ヴァイスフリューゲル　ランドソル支部", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 0, 11, "長妻樹里", 49, 15, 19, "クウカ（オーエド）", "小説を読むこと");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109601, 163, "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", 16, "O", "ヴァイスフリューゲル　ランドソル支部", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0, 8, "佐藤聡美", 51, 15, 31, "ニノン（オーエド）", "忍法開発");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (109701, 154, "鬼がかりの万能妹メイド", "鬼族", 17, "?", "？？？", "", 0, 2, "水瀬いのり", "??", "", 2, "レム", "演劇鑑賞、詩文");
