INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (110001, 167, "天真爛漫で人気者のカリスマモデル", "魔族", 17, "O", "ルーセント学院", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 0, 4, "上坂すみれ", 48, 14, 10, "スズナ（サマー）", "ファッション");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (110101, 162, "多くの男性を魅了する無垢な女教師", "魔族", 23, "B", "ルーセント学院", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 0, 8, "伊藤静", 52, 14, 14, "イオ（サマー）", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞");
