INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (110501, 158, "いつでも「なんくるないさ～」な天然娘", "獣人族", 17, "A", "自警団（カォン）", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 0, 7, "高森奈津美", 53, 10, 7, "カオリ（サマー）", "踊り、空手");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (110601, 155, "マホマホ王国のプリンセス", "獣人族", 16, "O", "自警団（カォン）", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0, 9, "内田真礼", 42, 10, 22, "マホ（サマー）", "空想、ぬいぐるみ集め");
