INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (111901, 140, "主を慕う、小さなガイド役", "エルフ", 11, "B", "美食殿", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0, 5, "伊藤美来", 35, 1, 11, "コッコロ（ニューイヤー）", "瞑想、動植物の飼育");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (112001, 152, "行き倒れの謎のネコミミ魔法使い", "獣人族", 14, "A", "美食殿", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 0, 9, "立花理香", 39, 1, 2, "キャル（ニューイヤー）", "猫と遊ぶ");
