INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (112901, 156, "人懐っこくてマシンガントークな妹系少女", "ヒューマン", 15, "A", "ラビリンス", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 0, 8, "阿澄佳奈", 44, 3, 25, "リノ（ワンダー）", "お裁縫");
