INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (113201, 159, "前世を信じる中二病患者、「疾風の冥姫」", "魔族", 17, "A", "トワイライトキャラバン", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 0, 7, "髙野麻美", 45, 13, 5, "アンナ（サマー）", "小説執筆");
