INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (114601, 164, "純情でほっとけない大人の女性", "エルフ", 22, "A", "メルクリウス財団", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 0, 3, "今井麻美", 55, 12, 16, "ユカリ（クリスマス）", "ウインドーショッピング");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (114701, 148, "さまよえる謎の少女", "ヒューマン", 16, "O", "？？？", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 0, 8, "潘めぐみ", 40, "", 11, "ムイミ（ニューイヤー）", "冒険、思い出話");
