INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (115501, 140, "主を慕う、小さなガイド役", "エルフ", 11, "B", "美食殿", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0, 5, "伊藤美来", 35, 1, 11, "コッコロ（儀装束）", "瞑想、動植物の飼育");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (115601, 158, "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 17, "O", "トゥインクルウィッシュ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0, 4, "種田梨沙", 47, 2, 5, "ユイ（儀装束）", "料理、人間観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (115701, 152, "頭脳明晰な美少女名探偵", "獣人族", 15, "AB", "自警団（カォン）", "", 0, 11, "水瀬いのり", 41, 10, 3, "カスミ（サマー）", "読書、推理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (115801, 150, "乙女チックなもふもふアニマル", "獣人族", 17, "A", "牧場（エリザベスパーク）", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 0, 3, "徳井青空", 100, 11, 14, "リマ（シンデレラ）", "毛繕い、お喋り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (115901, 168, "男勝りで情に厚いワイルド娘", "獣人族", 17, "O", "自警団（カォン）", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 0, 8, "小松未可子", 54, 10, 9, "マコト（シンデレラ）", "お菓子作り");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (116001, 155, "マホマホ王国のプリンセス", "獣人族", 16, "O", "自警団（カォン）", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0, 9, "内田真礼", 42, 10, 22, "マホ（シンデレラ）", "空想、ぬいぐるみ集め");
