INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (116701, 158, "「友達」に憧れる、エルフの森の女の子", "エルフ", 13, "AB", "フォレスティエ", "", 0, 6, "花澤香菜", 44, 6, 6, "アオイ（作業服）", "友達作りのイメトレ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (116801, 158, "弱きを助け強きをくじく猫娘", "獣人族", 19, "AB", "メルクリウス財団", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0, 3, "沼倉愛美", 48, 12, 1, "タマキ（作業服）", "猫とたわむれること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (116901, 163, "仕事も私事も効率優先な傭兵少女", "ヒューマン", 20, "O", "メルクリウス財団", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 0, 11, "田所あずさ", 49, 12, 11, "ミフユ（作業服）", "傭兵などのアルバイト");
