INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117101, 168, "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 18, "O", "ラビリンス", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0, 10, "生天目仁美", 54, 3, 24, "シズル（サマー）", "家事全般");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117201, 157, "歌って踊れる大人気アイドル", "ヒューマン", 17, "B", "カルミナ", "", 0, 1, "日笠陽子", 40, 4, 24, "ノゾミ（サマー）", "舞台鑑賞、ダンス");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117301, 163, "人々を守るために歌う、唱喚士の少女", "ヒューマン", 17, "O", "カルミナ", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 0, 6, "福原綾香", 46, 4, 3, "チカ（サマー）", "各種楽器");
