INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117501, 166, "実験が趣味の危険な科学者", "ヒューマン", 27, "A", "トワイライトキャラバン", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 0, 3, "三石琴乃", 53, 13, 7, "ミツキ（オーエド）", "研究、実験");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117601, 150, "ボクは誰よりも美しい", "エルフ", 14, "AB", "ヴァイスフリューゲル　ランドソル支部", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 0, 10, "大空直美", 40, 15, 10, "ユキ（オーエド）", "鏡で自分を見ること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117701, 158, "いつでも「なんくるないさ～」な天然娘", "獣人族", 17, "A", "自警団（カォン）", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 0, 7, "高森奈津美", 53, 10, 7, "カオリ（ハロウィン）", "踊り、空手");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (117801, 163, "トーゴクの神秘、オシエテクダサイ！", "ヒューマン", 16, "O", "ヴァイスフリューゲル　ランドソル支部", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 0, 8, "佐藤聡美", 51, 15, 31, "ニノン（ハロウィン）", "忍法開発");
