INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (119001, 162, "多くの男性を魅了する無垢な女教師", "魔族", 23, "B", "ルーセント学院", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 0, 8, "伊藤静", 52, 14, 14, "イオ（ノワール）", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞");
