INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (121301, 150, "泣き虫で臆病な守ってあげたい女の子", "ヒューマン", 12, "B", "サレンディア救護院", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 0, 6, "植田佳奈", 40, 9, 9, "クルミ（ステージ）", "観劇、おままごと");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (121401, 120, "ちょっとおませな恋に恋する女の子", "魔族", 11, "A", "ルーセント学院", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 0, 1, "久野美咲", 22, 14, 3, "ミサキ（ステージ）", "ファッション誌鑑賞、コスメ集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (121501, 155, "どこまでも一途に慕う、純情乙女", "エルフ", 16, "O", "ヴァイスフリューゲル　ランドソル支部", "", 0, 4, "大関英里", 43, 15, 7, "アユミ（怪盗）", "観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (121601, 145, "口が達者なヘタレドラゴン", "ドラゴン族", 13, "AB", "ドラゴンズネスト", "", 0, 9, "藤田茜", "???", 17, 29, "イノリ（怪盗）", "ゲーム");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (121901, 159, "前世を信じる中二病患者、「疾風の冥姫」", "魔族", 17, "A", "トワイライトキャラバン", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 0, 7, "髙野麻美", 45, 13, 5, "アンナ（パイレーツ）", "小説執筆");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122001, 157, "占いが得意な霊能少女", "魔族", 18, "AB", "悪魔偽王国軍（ディアボロス）", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 0, 12, "大坪由佳", 42, 7, 22, "シノブ（パイレーツ）", "占い");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122101, 158, "「友達」に憧れる、エルフの森の女の子", "エルフ", 13, "AB", "フォレスティエ", "", 0, 6, "花澤香菜", 44, 6, 6, "アオイ（キャンプ）", "友達作りのイメトレ");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122201, 164, "純情でほっとけない大人の女性", "エルフ", 22, "A", "メルクリウス財団", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 0, 3, "今井麻美", 55, 12, 16, "ユカリ（キャンプ）", "ウインドーショッピング");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122301, 149, "けんぞくのご主人様", "魔族", "??", "AB", "？？？", "", 0, 12, "釘宮理恵", 41, "", 6, "ヴァンピィ", "お散歩、お料理");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122401, 155, "人助けが大好き！　前向き格闘娘", "獣人族", 16, "A", "トゥインクルウィッシュ", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0, 8, "東山奈央", 44, 2, 27, "ヒヨリ（サマー）", "人助け、応援");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122501, 163, "クールで何事にも真っ直ぐな剣士", "魔族", 18, "B", "トゥインクルウィッシュ", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0, 1, "早見沙織", 46, 2, 12, "レイ（サマー）", "読書、乗馬、お茶");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122601, 158, "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 17, "O", "トゥインクルウィッシュ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0, 4, "種田梨沙", 47, 2, 5, "ユイ（サマー）", "料理、人間観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122701, 118, "礼儀正しくしっかり者のちびっ子優等生", "エルフ", 8, "A", "リトルリリカル", "", 0, 2, "小倉唯", 21, 5, 2, "キョウカ（サマー）", "お勉強");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122801, 128, "探検好きのイタズラっ子", "ヒューマン", 9, "O", "リトルリリカル", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 0, 8, "諸星すみれ", 27, 5, 10, "ミソギ（サマー）", "いたずら、探検");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (122901, 117, "お歌もにんじんも、ウサギさんも大好き♪", "獣人族", 10, "O", "リトルリリカル", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 0, 4, "日高里菜", 21, 5, 3, "ミミ（サマー）", "かわいいもの集め");
