INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (123101, 155, "マホマホ王国のプリンセス", "獣人族", 16, "O", "自警団（カォン）", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 0, 9, "内田真礼", 42, 10, 22, "マホ（エクスプローラー）", "空想、ぬいぐるみ集め");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (123201, 148, "ぷうきちといつも一緒！", "ヒューマン", 14, "B", "サレンディア救護院", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 0, 5, "芹澤優", 38, 9, 10, "アヤネ（エクスプローラー）", "屋内でできる遊び");
