INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (124701, 166, "実験が趣味の危険な科学者", "ヒューマン", 27, "A", "トワイライトキャラバン", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 0, 3, "三石琴乃", 53, 13, 7, "ミツキ（ニューイヤー）", "研究、実験");
