INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (125001, 148, "さまよえる謎の少女", "ヒューマン", 16, "O", "？？？", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", 0, 8, "潘めぐみ", 40, "", 11, "ムイミ（リベレイター）", "冒険、思い出話");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (125101, 158, "弱きを助け強きをくじく猫娘", "獣人族", 19, "AB", "メルクリウス財団", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 0, 3, "沼倉愛美", 48, 12, 1, "タマキ（カフェ）", "猫とたわむれること");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (125201, 140, "見た目も中身もお子ちゃまな異国の軍人", "ヒューマン", 17, "A", "ヴァイスフリューゲル　ランドソル支部", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 0, 7, "辻あゆみ", 33, 15, 28, "モニカ（カフェ）", "お菓子屋通い");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (125301, 140, "主を慕う、小さなガイド役", "エルフ", 11, "B", "美食殿", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 0, 5, "伊藤美来", 35, 1, 11, "コッコロ（レンジャー）", "瞑想、動植物の飼育");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (125401, 153, "読書が趣味の病弱少女", "獣人族", 14, "A", "牧場（エリザベスパーク）", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 0, 11, "小清水亜美", 40, 11, 3, "シオリ（レンジャー）", "読書、お散歩");
