INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (126101, 135, "正義の魂を受け継ぐ、爆食系天然天才娘", "獣人族", 10, "O", "アルターメイデン", "", 0, 3, "高尾奏音", 34, 20, 1, "プレシア（フォールン）", "ごはんをたべること");
