INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (136501, 168, "お姉ちゃんがお世話してあげるからねっ！", "ヒューマン", 18, "O", "ラビリンス", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 0, 10, "生天目仁美", 54, 3, 24, "シズル（ニューイヤー）", "家事全般");
