INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (180101, 155, "人助けが大好き！　前向き格闘娘", "獣人族", 16, "A", "トゥインクルウィッシュ", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 0, 8, "東山奈央", 44, 2, 27, "ヒヨリ（プリンセス）", "人助け、応援");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (180201, 158, "戦闘のサポートが得意な、心優しい少女", "ヒューマン", 17, "O", "トゥインクルウィッシュ", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 0, 4, "種田梨沙", 47, 2, 5, "ユイ（プリンセス）", "料理、人間観察");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (180301, 163, "クールで何事にも真っ直ぐな剣士", "魔族", 18, "B", "トゥインクルウィッシュ", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 0, 1, "早見沙織", 46, 2, 12, "レイ（プリンセス）", "読書、乗馬、お茶");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES (180401, 156, "いつも元気な腹ペコ少女", "ヒューマン", 17, "O", "美食殿", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 0, 3, "M・A・O", 46, 1, 31, "ぺコリーヌ（プリンセス）", "食べ歩き、料理");
